aftenposten-2022.text:
.mm-svp-front-video[href="https://www.aftenposten.no/video/i/nWr93d/kortfilm-kundebeskjed"] video {
  object-fit:cover!important;
}
.mm-svp-front-video[href="https://www.aftenposten.no/video/i/nWr93d/kortfilm-kundebeskjed"] .jw-controls {
  opacity:0!important;
  transition:all .15s!important;
}

.mm-svp-front-video[href="https://www.aftenposten.no/video/i/nWr93d/kortfilm-kundebeskjed"] div[data-svp-asset] {
  width:100%!important;
  height:100%!important;
}

.mm-svp-front-video .mm-stop-video {
  position:absolute;
  z-index:10;
  bottom:10px;
  left:10px;
  padding:8px 12px;
  border-radius:2em;
  background:#0433ff;
  color:#fff;
  font-family:Roboto, Helvetica, sans-serif;
  font-size:14px;
  text-align:center;
  line-height:1;
  cursor:pointer;
}
